function omg_call_builtin(name, args) {
    const fn = _omg_builtins[name];
    if (!fn) omg_panic('TypeError', 'unknown builtin: ' + name);
    return fn(...args);
}
_omg_builtins.call_builtin = omg_call_builtin;

// === Closure helper =======================================================

function omg_closure(fn, captured, name) {
    const wrapped = (...args) => fn(captured, ...args);
    wrapped.__omg_captured = captured;
    // Bare source name (no `__mod_N__` mangling) for traceback
    // rendering when this closure is invoked via CALL_VALUE.
    wrapped.__omg_name = name || '<closure>';
    return wrapped;
}

// String-named function table. Populated by the program preamble
// after every top-level MAKE_FUNC, so that CALL_VALUE on a string
// (which is what import-module dispatch produces) can resolve it.
const omg_func_table = new Map();
function omg_lookup_fn(name) {
    const fn = omg_func_table.get(name);
    if (!fn) omg_panic('UndefinedIdentError', name);
    return fn;
}

